import os

from django import template
from django.contrib.staticfiles import finders
from django.templatetags.static import static
from django.utils.safestring import mark_safe

register = template.Library()


@register.simple_tag
def versioned_static(path):
    """{% static %} plus a `?v=<mtime>` cache-buster.

    The compiled Tailwind CSS is rebuilt by a separate `tailwind build` process
    that doesn't restart the Django dev server, and its URL has no content hash
    (ManifestStaticFilesStorage's hashing only applies to files collectstatic has
    processed). Without this, browsers can keep serving a stale cached copy after
    a rebuild — bump the query string from the file's real mtime so every rebuild
    is a new URL.
    """
    url = static(path)
    found = finders.find(path)
    if found:
        try:
            url = f"{url}?v={int(os.path.getmtime(found))}"
        except OSError:
            pass
    return url

