@register.simple_tag
def nav_icon(name, css_class="h-5 w-5"):
    path = _ICON_PATHS.get(name, "")
    return mark_safe(
        f'<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" '
        f'stroke-width="1.5" stroke="currentColor" class="{css_class} shrink-0">{path}</svg>'
    )

STATUS_BADGE_CLASSES = {
    "success": "bg-green-100 dark:bg-green-500/15 text-green-800 dark:text-green-300",
    "info": "bg-blue-100 dark:bg-blue-500/15 text-blue-800 dark:text-blue-300",
    "warning": "bg-amber-100 dark:bg-amber-500/15 text-amber-800 dark:text-amber-300",
    "danger": "bg-red-100 dark:bg-red-500/15 text-red-800 dark:text-red-300",
    "neutral": "bg-gray-100 dark:bg-slate-700/50 text-gray-700 dark:text-slate-300",
}


@register.simple_tag
def status_badge(label, tone="neutral"):
    classes = STATUS_BADGE_CLASSES.get(tone, STATUS_BADGE_CLASSES["neutral"])
    return template.loader.render_to_string(
        "core/components/status_badge.html", {"label": label, "classes": classes}
    )
